def bad_title(s: str) -> str:
    return s.title()

def good_title(s: str) -> str:
    parts = s.split()
    keep = {"de", "del", "la", "las", "los", "y"}
    out = []
    for i, p in enumerate(parts):
        if i > 0 and p.casefold() in keep:
            out.append(p.casefold())
        else:
            out.append(p[:1].upper() + p[1:].lower() if p else p)
    return " ".join(out)

def test(fn):
    out = fn("juan de la cruz")
    assert out == "Juan de la Cruz", out
    return "pass"

try:
    test(bad_title)
    print("RED unexpected")
except AssertionError:
    print("RED")
print("GREEN", test(good_title))

def mask_email(email: str) -> str:
    local, _, domain = email.partition("@")
    if not local:
        return "***@" + domain
    return local[0] + "***@" + domain

def mask_phone(phone: str) -> str:
    digits = "".join(c for c in phone if c.isdigit())
    return "***" + digits[-4:]

print(mask_email("carlos@ejemplo.pe"))
print(mask_phone("+51 988 777 666"))

