def process_batch(rows):
    ok, q = [], []
    for r in rows:
        if not r.get("id"):
            q.append({"row": r, "reason": "data:missing_id"})
        else:
            ok.append(r)
    return {"ok": ok, "quarantined": q, "in": len(rows)}

