retry = {
    "TimeoutError": "yes",
    "ValueError": "no",
    "ConnectionError": "yes",
    "KeyError": "no",
    "PermissionError": "no",
}
for e, r in retry.items():
    print(f"{e}: {r}")

def retry_call(fn, max_attempts=3):
    last = None
    for _ in range(max_attempts):
        try:
            return fn()
        except TimeoutError as e:
            last = e
    raise last

n = {"c": 0}

def flaky():
    n["c"] += 1
    if n["c"] < 3:
        raise TimeoutError("x")
    return "done"

print(retry_call(flaky), "calls", n["c"])
